sql:
SELECT COUNT(DISTINCT model_id) 
FROM vehicle_statistics 
WHERE avgPrice > 1000;

SELECT AVG(avgPrice) AS average_price
FROM vehicle_statistics
WHERE year = 1991 AND fuel_type = 'gasoline';

SELECT avgPrice, fuel_type
FROM vehicle_statistics
WHERE year = 1991;

external_knowledge:
- "environmental impact" refers to the average CO2 emissions of the vehicle model;
- "financial prestige" refers to the highest average price of the vehicle model;
- "sturdy" and "majestic" are metaphors to describe the vehicle model with the highest average emissions and price.

sql:
SELECT MAX(avgPrice) AS highest_avg_price
FROM vehicle_statistics
WHERE fuel_type = 'diesel';

external_knowledge:
- 'gasoline' refers to vehicles that use gasoline as fuel;
- 'manual transmission' refers to vehicles with a manual gear shift;
- 'sedan' refers to a type of car body with a fixed roof and usually four doors.

sql:
SELECT COUNT(model_id) AS model_count
FROM vehicle_models
WHERE fuel_type = 'gasoline' AND transmission_type = 'manual' AND body_type = 'sedan';

external_knowledge:
